class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    # Helper to get the node corresponding to the end of a word
    # Returns None if the word path does not exist.
    def _get_node(self, word: str) -> TrieNode | None:
        node = self.root
        for char in word:
            if char not in node.children:
                return None
            node = node.children[char]
        return node

    # Checks if a *full* string is currently marked as a word in the trie.
    def is_word(self, word: str) -> bool:
        node = self._get_node(word)
        return node is not None and node.is_end_of_word

    # Temporarily changes the 'is_end_of_word' status for a specific word.
    def set_word_status(self, word: str, status: bool) -> None:
        node = self._get_node(word)
        if node:
            node.is_end_of_word = status

def findConcatenatedWords(words: list[str]) -> list[str]:
    if not words:
        return []

    main_trie = Trie()
    # Insert all non-empty words into the trie.
    # The trie will be used to quickly check if a substring is a valid word.
    for word in words:
        if word: # Ensure no empty string is inserted
            main_trie.insert(word)

    result = []

    # Helper function using dynamic programming to check if a word can be broken
    # into at least two smaller words from the input set.
    def _can_break_word_dp(target_word: str) -> bool:
        n = len(target_word)
        if n == 0:
            return False

        # dp[i] will store True if target_word[:i] can be formed by
        # concatenating words that are currently active in `main_trie`.
        dp = [False] * (n + 1)
        dp[0] = True # An empty prefix can always be formed (base case for 0 words)

        # Iterate through all possible end points for a prefix
        for i in range(1, n + 1):
            # Iterate through all possible start points for a segment ending at `i`
            for j in range(i):
                # If target_word[:j] can be formed, and target_word[j:i] is a valid word
                if dp[j]:
                    sub = target_word[j:i]
                    # Check if 'sub' is a valid word using the trie.
                    # This respects the temporary 'is_end_of_word' status.
                    if main_trie.is_word(sub):
                        dp[i] = True
                        break # Found a way to form target_word[:i], move to the next 'i'

        # If dp[n] is True, it means target_word can be fully segmented.
        # Since we temporarily disabled `target_word` itself as a single component,
        # dp[n] can only be True if it's formed by at least two components.
        return dp[n]

    # Iterate through the original input words to check them.
    for word in words:
        if not word: # Skip empty strings as they cannot be concatenated words
            continue

        # Temporarily remove the current `word` from consideration as a single component.
        # This ensures that `word` must be formed by at least two *other* words from the list.
        main_trie.set_word_status(word, False)

        if _can_break_word_dp(word):
            result.append(word)

        # Re-add the `word` back to consideration for subsequent checks.
        main_trie.set_word_status(word, True)

    return result
